1754→    void moveOrCopyMessageSynchronous(Account account, long srcFolderId, List<LocalMessage> inMessages,
1755→            long destFolderId, MoveOrCopyFlavor operation) {
1756→
1757→        if (operation == MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ) {
1758→            throw new UnsupportedOperationException("MOVE_AND_MARK_AS_READ unsupported");
1759→        }
1760→
1761→        try {
1762→            LocalStore localStore = localStoreProvider.getInstance(account);
1763→            if (operation == MoveOrCopyFlavor.MOVE && !isMoveCapable(account)) {
1764→                return;
1765→            }
1766→            if (operation == MoveOrCopyFlavor.COPY && !isCopyCapable(account)) {
1767→                return;
1768→            }
1769→
1770→            LocalFolder localSrcFolder = localStore.getFolder(srcFolderId);
1771→            localSrcFolder.open();
1772→
1773→            LocalFolder localDestFolder = localStore.getFolder(destFolderId);
1774→            localDestFolder.open();
1775→
1776→            boolean unreadCountAffected = false;
1777→            List<String> uids = new LinkedList<>();
1778→            for (Message message : inMessages) {
1779→                String uid = message.getUid();
1780→                if (!uid.startsWith(K9.LOCAL_UID_PREFIX)) {
1781→                    uids.add(uid);
1782→                }
1783→
1784→                if (!unreadCountAffected && !message.isSet(Flag.SEEN)) {
1785→                    unreadCountAffected = true;
1786→                }
1787→            }
1788→
1789→            List<LocalMessage> messages = localSrcFolder.getMessagesByUids(uids);
1790→            if (messages.size() > 0) {
1791→                Timber.i("moveOrCopyMessageSynchronous: source folder = %s, %d messages, destination folder = %s, " +
1792→                        "operation = %s", srcFolderId, messages.size(), destFolderId, operation.name());
1793→
1794→                MessageStore messageStore = messageStoreManager.getMessageStore(account);
1795→
1796→                List<Long> messageIds = new ArrayList<>();
1797→                Map<Long, String> messageIdToUidMapping = new HashMap<>();
1798→                for (LocalMessage message : messages) {
1799→                    long messageId = message.getDatabaseId();
1800→                    messageIds.add(messageId);
1801→                    messageIdToUidMapping.put(messageId, message.getUid());
1802→                }
1803→
1804→                Map<Long, Long> resultIdMapping;
1805→                if (operation == MoveOrCopyFlavor.COPY) {
1806→                    resultIdMapping = messageStore.copyMessages(messageIds, destFolderId);
1807→
1808→                    if (unreadCountAffected) {
1809→                        // If this copy operation changes the unread count in the destination
1810→                        // folder, notify the listeners.
1811→                        for (MessagingListener l : getListeners()) {
1812→                            l.folderStatusChanged(account, destFolderId);
1813→                        }
1814→                    }
1815→                } else {
1816→                    resultIdMapping = messageStore.moveMessages(messageIds, destFolderId);
1817→
1818→                    unsuppressMessages(account, messages);
1819→
1820→                    if (unreadCountAffected) {
1821→                        // If this move operation changes the unread count, notify the listeners
1822→                        // that the unread count changed in both the source and destination folder.
1823→                        for (MessagingListener l : getListeners()) {
1824→                            l.folderStatusChanged(account, srcFolderId);
1825→                            l.folderStatusChanged(account, destFolderId);
1826→                        }
1827→                    }
1828→                }
1829→
1830→                Map<Long, String> destinationMapping = messageStore.getMessageServerIds(resultIdMapping.values());
1831→
1832→                Map<String, String> uidMap = new HashMap<>();
1833→                for (Entry<Long, Long> entry : resultIdMapping.entrySet()) {
1834→                    long sourceMessageId = entry.getKey();
1835→                    long destinationMessageId = entry.getValue();
1836→
1837→                    String sourceUid = messageIdToUidMapping.get(sourceMessageId);
1838→                    String destinationUid = destinationMapping.get(destinationMessageId);
1839→                    uidMap.put(sourceUid, destinationUid);
1840→                }
1841→
1842→                queueMoveOrCopy(account, localSrcFolder.getDatabaseId(), localDestFolder.getDatabaseId(),
1843→                        operation, uidMap);
1844→            }
1845→
1846→            processPendingCommands(account);
1847→        } catch (MessagingException me) {
1848→            throw new RuntimeException("Error moving message", me);
1849→        }
1850→    }
