1071→    private void setFlagSynchronous(final Account account, final List<Long> ids,
1072→            final Flag flag, final boolean newState, final boolean threadedList) {
1073→
1074→        LocalStore localStore;
1075→        try {
1076→            localStore = localStoreProvider.getInstance(account);
1077→        } catch (MessagingException e) {
1078→            Timber.e(e, "Couldn't get LocalStore instance");
1079→            return;
1080→        }
1081→
1082→        // Update affected messages in the database. This should be as fast as possible so the UI
1083→        // can be updated with the new state.
1084→        try {
1085→            if (threadedList) {
1086→                localStore.setFlagForThreads(ids, flag, newState);
1087→                removeFlagForThreadsFromCache(account, ids, flag);
1088→            } else {
1089→                localStore.setFlag(ids, flag, newState);
1090→                removeFlagFromCache(account, ids, flag);
1091→            }
1092→        } catch (MessagingException e) {
1093→            Timber.e(e, "Couldn't set flags in local database");
1094→        }
1095→
1096→        // Read folder ID and UID of messages from the database
1097→        Map<Long, List<String>> folderMap;
1098→        try {
1099→            folderMap = localStore.getFolderIdsAndUids(ids, threadedList);
1100→        } catch (MessagingException e) {
1101→            Timber.e(e, "Couldn't get folder name and UID of messages");
1102→            return;
1103→        }
1104→
1105→        boolean accountSupportsFlags = supportsFlags(account);
1106→
1107→        // Loop over all folders
1108→        for (Entry<Long, List<String>> entry : folderMap.entrySet()) {
1109→            long folderId = entry.getKey();
1110→            List<String> uids = entry.getValue();
1111→
1112→            // Notify listeners of changed folder status
1113→            for (MessagingListener l : getListeners()) {
1114→                l.folderStatusChanged(account, folderId);
1115→            }
1116→
1117→            if (flag == Flag.SEEN && newState) {
1118→                cancelNotificationsForMessages(account, folderId, uids);
1119→            }
1120→
1121→            if (accountSupportsFlags) {
1122→                LocalFolder localFolder = localStore.getFolder(folderId);
1123→                try {
1124→                    localFolder.open();
1125→                    if (!localFolder.isLocalOnly()) {
1126→                        // Send flag change to server
1127→                        queueSetFlag(account, folderId, newState, flag, uids);
1128→                        processPendingCommands(account);
1129→                    }
1130→                } catch (MessagingException e) {
1131→                    Timber.e(e, "Couldn't open folder. Account: %s, folder ID: %d", account, folderId);
1132→                }
1133→            }
1134→        }
